}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x)
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel_omp(
    int data_5,
    int *var_15,
    int *item_25,
    int *elem_31,
    int v_38,
    int data_11,
    int x_23,
    int val_19,
    int num_blocks)
{
    #pragma omp parallel for schedule(dynamic)
    for (int elem_16 = 0; elem_16 < num_blocks; elem_16++) {
        int var_34[BLOCK_SIZE];
        int x_22[BLOCK_SIZE];

        int elem_24 = BLOCK_SIZE - data_5 * HALO * 2;
        int item_30 = elem_24 * elem_16 - val_19;
        int x_10 = item_30 + BLOCK_SIZE - 1;

        for (int data_3 = 0; data_3 < BLOCK_SIZE; data_3++) {
            int data_21 = item_30 + data_3;
            if (IN_RANGE(data_21, 0, v_38 - 1)) {
                var_34[data_3] = item_25[data_21];
            }
        }

        int tmp_27_base = (0 > item_30) ? -item_30 : 0;
        int val_41_base = (v_38 - 1 < x_10) ? BLOCK_SIZE - 1 - (x_10 - v_38 + 1) : BLOCK_SIZE - 1;

        bool tmp_6_arr[BLOCK_SIZE];
        memset(tmp_6_arr, 0, sizeof(tmp_6_arr));

        for (int i = 0; data_5 > i; i++) {
            for (int data_3 = 0; data_3 < BLOCK_SIZE; data_3++) {
                tmp_6_arr[data_3] = false;
            }

            for (int data_3 = 0; data_3 < BLOCK_SIZE; data_3++) {
                int data_21 = item_30 + data_3;
                bool tmp_26 = IN_RANGE(data_3, tmp_27_base, val_41_base);

                if (IN_RANGE(data_3, i + 1, BLOCK_SIZE - i - 2) && tmp_26) {
                    tmp_6_arr[data_3] = true;
                    int W = data_3 - 1;
                    int E = data_3 + 1;
                    W = (tmp_27_base > W) ? tmp_27_base : W;
                    E = (val_41_base < E) ? val_41_base : E;

                    int left = var_34[W];
                    int x_39 = var_34[data_3];
                    int right = var_34[E];
                    int elem_28 = MIN(left, x_39);
                    elem_28 = MIN(elem_28, right);
                    int elem_35 = v_38 * (x_23 + i) + data_21;
                    x_22[data_3] = elem_28 + var_15[elem_35];
                }
            }

            if (data_5 - 1 == i)
                break;

            for (int data_3 = 0; data_3 < BLOCK_SIZE; data_3++) {
                if (tmp_6_arr[data_3])
                    var_34[data_3] = x_22[data_3];
            }
        }

        for (int data_3 = 0; data_3 < BLOCK_SIZE; data_3++) {
            int data_21 = item_30 + data_3;
            if (tmp_6_arr[data_3]) {
                elem_31[data_21] = x_22[data_3];
            }
        }
    }
}

int calc_path(int *val_7, int *elem_37[2], int x_0, int var_1,
              int x_2, int tmp_32, int tmp_36)
{
    int v_40 = 1, tmp_14 = 0;
    for (int t = 0; x_0 - 1 > t; t += x_2) {
        int x_42 = v_40;
        v_40 = tmp_14;
        tmp_14 = x_42;

        dynproc_kernel_omp(
            MIN(pyramid_height, rows - t - 1),
            val_7, elem_37[v_40], elem_37[tmp_14],
            var_1, x_0, t, tmp_36,
            tmp_32);
    }
    return tmp_14;
}

